// decode_video.c - فك ترميز فيديو خطوة بخطوة
#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>
#include <stdio.h>

int main(int argc, char **argv) {
    const char *filename = argc > 1 ? argv[1] : "input.mp4";
    AVFormatContext *fmt_ctx = NULL;
    const AVCodec *codec = NULL;
    AVCodecContext *codec_ctx = NULL;
    AVFrame *frame = av_frame_alloc();
    AVPacket *pkt = av_packet_alloc();
    int ret;

    // 1. فتح ملف الوسائط
    if (avformat_open_input(&fmt_ctx, filename, NULL, NULL) < 0) {
        fprintf(stderr, "فشل فتح الملف\n");
        return 1;
    }

    // 2. البحث عن stream فيديو
    ret = av_find_best_stream(fmt_ctx, AVMEDIA_TYPE_VIDEO, -1, -1, 0, NULL);
    if (ret < 0) {
        fprintf(stderr, "لا يوجد stream فيديو\n");
        return 1;
    }
    int stream_idx = ret;

    // 3. إيجاد الـ decoder
    codec = avcodec_find_decoder(fmt_ctx->streams[stream_idx]->codecpar->codec_id);
    codec_ctx = avcodec_alloc_context3(codec);
n    avcodec_parameters_to_context(codec_ctx, fmt_ctx->streams[stream_idx]->codecpar);
    avcodec_open2(codec_ctx, codec, NULL);

    printf("Codec: %s\n", codec->long_name);
    printf("Resolution: %dx%d\n", codec_ctx->width, codec_ctx->height);
    printf("Pixel Format: %s\n", av_get_pix_fmt_name(codec_ctx->pix_fmt));

    // 4. قراءة packets وفك الترميز
    int frame_count = 0;
    while (av_read_frame(fmt_ctx, pkt) >= 0) {
        if (pkt->stream_index == stream_idx) {
            avcodec_send_packet(codec_ctx, pkt);
            while (avcodec_receive_frame(codec_ctx, frame) >= 0) {
                printf("frame #%d: %dx%d pts=%ld\n",
                       ++frame_count, frame->width, frame->height, frame->pts);
            }
        }
        av_packet_unref(pkt);
    }

    printf("Total frames: %d\n", frame_count);

    // 5. التنظيف
    av_frame_free(&frame);
    av_packet_free(&pkt);
    avcodec_free_context(&codec_ctx);
    avformat_close_input(&fmt_ctx);
    return 0;
}

