// decode_video.c - مثال فك ترميز فيديو من FFmpeg
// يوضح المسار الأساسي: فتح ملف -> إيجاد stream -> فتح codec -> قراءة packets -> فك الترميز -> حفظ frames

#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>
#include <libavutil/imgutils.h>

int main(int argc, char **argv) {
    const char *filename = argv[1];
    AVFormatContext *fmt_ctx = NULL;
    const AVCodec *codec = NULL;
    AVCodecContext *codec_ctx = NULL;
    AVFrame *frame = av_frame_alloc();
    AVPacket *pkt = av_packet_alloc();
    int ret;

    // 1. فتح ملف الوسائط
    ret = avformat_open_input(&fmt_ctx, filename, NULL, NULL);
    if (ret < 0) return ret;

    // 2. استخراج معلومات الـ streams
    ret = avformat_find_stream_info(fmt_ctx, NULL);
    if (ret < 0) return ret;

    // 3. إيجاد decoder لـ video stream
    ret = av_find_best_stream(fmt_ctx, AVMEDIA_TYPE_VIDEO, -1, -1, 0, NULL);
    if (ret < 0) return ret;
    int stream_idx = ret;
    AVCodecParameters *codec_par = fmt_ctx->streams[stream_idx]->codecpar;
    codec = avcodec_find_decoder(codec_par->codec_id);

    // 4. إنشاء codec context وفتحه
    codec_ctx = avcodec_alloc_context3(codec);
    avcodec_parameters_to_context(codec_ctx, codec_par);
    avcodec_open2(codec_ctx, codec, NULL);

    // 5. قراءة packets وفك الترميز
    while (av_read_frame(fmt_ctx, pkt) >= 0) {
        if (pkt->stream_index == stream_idx) {
            ret = avcodec_send_packet(codec_ctx, pkt);
            while (ret >= 0) {
                ret = avcodec_receive_frame(codec_ctx, frame);
                if (ret == AVERROR(EAGAIN) || ret == AVERROR_EOF) break;
                // هنا يمكنك معالجة frame->data و frame->width/height
            }
        }
        av_packet_unref(pkt);
    }

    avcodec_free_context(&codec_ctx);
    avformat_close_input(&fmt_ctx);
    av_frame_free(&frame);
    av_packet_free(&pkt);
    return 0;
}
